const item = $input.first().json;

// Sem documento → direto para fila humana
if (!item.conteudo_texto) {
  return [{ json: { ...item, skip_agent: true, motivo: 'sem_documento' } }];
}

// Prepara prompt para o agente validador
const conteudo_truncado = item.conteudo_texto.substring(0, 4000);

const prompt = `Você é um agente especialista em validação de informações sobre produtos e serviços.

Documentação disponível para "${item.produto_servico_nome || item.produto_servico_detectado || 'produto não identificado'}":
---
${conteudo_truncado}
---

Resposta do atendente que precisa ser validada:
"${item.resposta_texto}"

${item.contexto_conversa ? `Contexto da conversa:\n${item.contexto_conversa}` : ''}

Tarefa: Verifique se a resposta do atendente está CORRETA com base na documentação.

Retorne APENAS um JSON válido (sem markdown):
{
  "resultado": "correta" | "incorreta" | "sem_informacao",
  "confianca": 0.0 a 1.0,
  "trecho_base": "trecho exato da documentação que embasou esta validação (null se sem_informacao)",
  "observacao": "explicação concisa do resultado",
  "sugestao_correcao": "resposta correta que deveria ter sido dada (apenas se resultado=incorreta, null caso contrário)"
}

Se não encontrar informação suficiente na documentação para validar, use resultado="sem_informacao".`;

return [{ json: { ...item, skip_agent: false, prompt } }];

