const ctx = $('preparar-prompt-validacao').first().json;
const claudeResponse = $input.first().json;

let validacao;
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  validacao = JSON.parse(content);
} catch(e) {
  validacao = { resultado: 'sem_informacao', confianca: 0, observacao: 'Erro ao processar resposta do agente' };
}

return [{ json: { ...ctx, validacao } }];
